  static List<Map<String, dynamic>> slice(
    String language, {
    int offset = 0,
    int count = 24,
  }) {
    final code = language.isEmpty ? 'en' : language;
    final raw = List<Map<String, dynamic>>.from(_pools[code] ?? _pools['en']!);
    if (raw.isEmpty) return [];
    final start = offset % raw.length;
    final out = <Map<String, dynamic>>[];
    for (var i = 0; i < count && i < raw.length; i++) {
      out.add(raw[(start + i) % raw.length]);
    }
    return out;
  }

  static List<String> translationsFor(String language, {int limit = 30}) {
    return slice(language, count: limit)
        .map((m) => m['translation'] as String)
        .toSet()
        .toList();
  }
